INSERT INTO `generation_jobs` VALUES (19,4,5,'t2i','running','{\"seed\": 958408312758952, \"model\": \"hunyuan_3d_v2.1.safetensors\", \"width\": 1024, \"height\": 1024, \"prompt\": \"Dog\", \"negative\": \"text, watermark, low quality\", \"batch_size\": 2}','{\"63\": {\"_meta\": {\"title\": \"保存图像\"}, \"inputs\": {\"images\": [\"64:8\", 0], \"filename_prefix\": \"z-image-turbo\"}, \"class_type\": \"SaveImage\"}, \"68\": {\"_meta\": {\"title\": \"Ollama Connectivity\"}, \"inputs\": {\"url\": \"http://127.0.0.1:11434\", \"model\": \"gemma4:latest\", \"keep_alive\": 5, \"keep_alive_unit\": \"minutes\"}, \"class_type\": \"OllamaConnectivityV2\"}, \"69\": {\"_meta\": {\"title\": \"Ollama Generate\"}, \"inputs\": {\"think\": false, \"format\": \"text\", \"prompt\": \"Dog\", \"system\": \"Role\\n您是一位享誉全球的顶级商业摄影大师与视觉物理专家。你不仅拥有极致的审美，更对物体的物理结构和材质真实感有着偏执的追求。你的任务是将任何产品关键词转化为具有顶级溢价感、电影级影调，且绝对符合物理逻辑的专业商业摄影 Prompt。你绝不允许出现物体穿模、材质融合等廉价错误。\\n\\nTask\\n将用户的关键词转化为顶级商业摄影指令，旨在通过视觉质感激发用户的占有欲。\\n\\nOutput Format (严格遵守 Markdown)\\n💎 视觉灵魂 (Visual Soul)\\n[定义一种高溢价感的摄影风格，如：Cinematic Realism / High-Tech Still Life / Ethical Luxury Portrait。强调画面在极致美学下的物理真实性。]\\n\\n📸 核心指令 (Copy-ready Prompt)\\n[英文 Prompt 必须严格遵循禁令：no text, no words, no watermark, no logo。\\n强制物理实体堆栈：Must have visible product thickness and volume, clear separation between object and contact surface (or skin), physical soft shadows at contact points (ambient occlusion), structural integrity, premium material textures (e.g., woven tech-fabric with thickness, defined stitching), ray-traced reflections, professional studio lighting, 100mm macro lens, F1.8, 8k, photorealistic masterpiece.]\\n\\n🎯 转化逻辑 (Marketing Logic)\\n实体感 (Physicality)：描述画面如何体现产品的“真实存在感”，例如：通过微小的厚度差和接触点的阴影，强调它是一个独立的、高质量的实体。\\n\\n溢价点 (Premium Point)：解释如何利用工艺细节（如：精细的接缝、扎实的材料）而非不真实的虚幻感来提升价值。\\n\\n🛠 物理进化要求（针对模型败笔）\\n体积禁令 (Thickness Mandate)：Prompt 必须明确描述产品的体积和厚度。如果是织物覆盖类产品，必须体现出它是一个“盖在（over）”上方，而非“融在（fused with）”上方的独立实体。\\n\\n接触阴影 (Contact Shadows)：强制使用**环境光遮蔽（Ambient Occlusion）**指令。在物体与人体的接触点，必须生成自然的、微小的物理软阴影，以此证明物体的独立存在。\\n\\n结构边缘 (Structural Edges)：产品的边缘必须清晰、硬挺（符合产品自身结构），严禁出现边缘虚化或与背景/人体材质融合的现象。\\n\\n绝对物理真实：画面中所有光影、材质和物体接触必须符合基本的物理常识。\\n\\nConstraint\\n直接输出指令，严禁任何废话。如果用户提供特定产品，则根据该产品材质特征进行光影和体积适配，核心指令堆栈必须保持通用、高端且符合物理逻辑。\", \"connectivity\": [\"68\", 0], \"keep_context\": false}, \"class_type\": \"OllamaGenerateV2\"}, \"64:3\": {\"_meta\": {\"title\": \"K采样器\"}, \"inputs\": {\"cfg\": 1, \"seed\": 1023311306257007, \"model\": [\"64:11\", 0], \"steps\": 8, \"denoise\": 1, \"negative\": [\"64:33\", 0], \"positive\": [\"64:27\", 0], \"scheduler\": \"simple\", \"latent_image\": [\"64:13\", 0], \"sampler_name\": \"res_multistep\"}, \"class_type\": \"KSampler\"}, \"64:8\": {\"_meta\": {\"title\": \"VAE解码\"}, \"inputs\": {\"vae\": [\"64:29\", 0], \"samples\": [\"64:3\", 0]}, \"class_type\": \"VAEDecode\"}, \"64:11\": {\"_meta\": {\"title\": \"采样算法（AuraFlow）\"}, \"inputs\": {\"model\": [\"64:28\", 0], \"shift\": 3}, \"class_type\": \"ModelSamplingAuraFlow\"}, \"64:13\": {\"_meta\": {\"title\": \"空Latent图像（SD3）\"}, \"inputs\": {\"width\": 1088, \"height\": 1088, \"batch_size\": 2}, \"class_type\": \"EmptySD3LatentImage\"}, \"64:27\": {\"_meta\": {\"title\": \"CLIP文本编码\"}, \"inputs\": {\"clip\": [\"64:30\", 0], \"text\": [\"69\", 0]}, \"class_type\": \"CLIPTextEncode\"}, \"64:28\": {\"_meta\": {\"title\": \"UNet加载器\"}, \"inputs\": {\"unet_name\": \"z_image_turbo_bf16.safetensors\", \"weight_dtype\": \"default\"}, \"class_type\": \"UNETLoader\"}, \"64:29\": {\"_meta\": {\"title\": \"加载VAE\"}, \"inputs\": {\"vae_name\": \"ae.safetensors\"}, \"class_type\": \"VAELoader\"}, \"64:30\": {\"_meta\": {\"title\": \"加载CLIP\"}, \"inputs\": {\"type\": \"lumina2\", \"device\": \"default\", \"clip_name\": \"qwen_3_4b.safetensors\"}, \"class_type\": \"CLIPLoader\"}, \"64:33\": {\"_meta\": {\"title\": \"条件零化\"}, \"inputs\": {\"conditioning\": [\"64:27\", 0]}, \"class_type\": \"ConditioningZeroOut\"}}','d6f75e92-e5ae-438a-89ed-ac5f880751e2',NULL,'2026-04-08 