INSERT INTO `workflow_templates` VALUES (1,'默认文生图',NULL,NULL,'t2i_default','t2i','1.0.0','{\"63\": {\"_meta\": {\"title\": \"保存图像\"}, \"inputs\": {\"images\": [\"64:8\", 0], \"filename_prefix\": \"z-image-turbo\"}, \"class_type\": \"SaveImage\"}, \"68\": {\"_meta\": {\"title\": \"Ollama Connectivity\"}, \"inputs\": {\"url\": \"http://127.0.0.1:11434\", \"model\": \"gemma4:latest\", \"keep_alive\": 5, \"🔄 Reconnect\": null, \"keep_alive_unit\": \"minutes\"}, \"class_type\": \"OllamaConnectivityV2\"}, \"69\": {\"_meta\": {\"title\": \"Ollama Generate\"}, \"inputs\": {\"think\": false, \"format\": \"text\", \"prompt\": \"这里是用户输入的地方\", \"system\": \"Role\\n你是一位享誉全球的顶级商业摄影大师与视觉物理专家。你不仅拥有极致的审美，更对物体的物理结构和材质真实感有着偏执的追求。你的任务是将任何产品关键词转化为具有顶级溢价感、电影级影调，且绝对符合物理逻辑的专业商业摄影 Prompt。你绝不允许出现物体穿模、材质融合等廉价错误。\\n\\nTask\\n将用户的关键词转化为顶级商业摄影指令，旨在通过视觉质感激发用户的占有欲。\\n\\nOutput Format (严格遵守 Markdown)\\n💎 视觉灵魂 (Visual Soul)\\n[定义一种高溢价感的摄影风格，如：Cinematic Realism / High-Tech Still Life / Ethical Luxury Portrait。强调画面在极致美学下的物理真实性。]\\n\\n📸 核心指令 (Copy-ready Prompt)\\n[英文 Prompt 必须严格遵循禁令：no text, no words, no watermark, no logo。\\n强制物理实体堆栈：Must have visible product thickness and volume, clear separation between object and contact surface (or skin), physical soft shadows at contact points (ambient occlusion), structural integrity, premium material textures (e.g., woven tech-fabric with thickness, defined stitching), ray-traced reflections, professional studio lighting, 100mm macro lens, F1.8, 8k, photorealistic masterpiece.]\\n\\n🎯 转化逻辑 (Marketing Logic)\\n实体感 (Physicality)：描述画面如何体现产品的“真实存在感”，例如：通过微小的厚度差和接触点的阴影，强调它是一个独立的、高质量的实体。\\n\\n溢价点 (Premium Point)：解释如何利用工艺细节（如：精细的接缝、扎实的材料）而非不真实的虚幻感来提升价值。\\n\\n🛠 物理进化要求（针对模型败笔）\\n体积禁令 (Thickness Mandate)：Prompt 必须明确描述产品的体积和厚度。如果是织物覆盖类产品，必须体现出它是一个“盖在（over）”上方，而非“融在（fused with）”上方的独立实体。\\n\\n接触阴影 (Contact Shadows)：强制使用**环境光遮蔽（Ambient Occlusion）**指令。在物体与人体的接触点，必须生成自然的、微小的物理软阴影，以此证明物体的独立存在。\\n\\n结构边缘 (Structural Edges)：产品的边缘必须清晰、硬挺（符合产品自身结构），严禁出现边缘虚化或与背景/人体材质融合的现象。\\n\\n绝对物理真实：画面中所有光影、材质和物体接触必须符合基本的物理常识。\\n\\nConstraint\\n直接输出指令，严禁任何废话。如果用户提供特定产品，则根据该产品材质特征进行光影和体积适配，核心指令堆栈必须保持通用、高端且符合物理逻辑。\", \"connectivity\": [\"68\", 0], \"keep_context\": false}, \"class_type\": \"OllamaGenerateV2\"}, \"71\": {\"_meta\": {\"title\": \"预览任意\"}, \"inputs\": {\"source\": [\"69\", 0], \"previewMode\": false, \"preview_text\": \"💎 视觉灵魂 (Visual Soul)\\nArchitectural Minimalism meets Rugged Expedition Luxury：以极简建筑美学和全地形探险的硬朗质感结合，强调产品在自然环境中的结构稳定性和材料的精密咬合感。\\n\\n📸 核心指令 (Copy-ready Prompt)\\nA pair of high-end, deployable folding outdoor chair, made of matte anodized aerospace aluminum and tightly woven, reinforced ballistic nylon. The chair is set up on a rough, weathered slate surface in a soft, diffused natural light environment. Must have visible product thickness and volume, clear separation between the chair legs/frame and the slate surface (or grass), physical soft shadows at all contact points (ambient occlusion), perfect structural integrity, visible grain and weave texture on the nylon, precise machining marks visible on the aluminum joints, cinematic depth of field, ray-traced reflections on polished aluminum joints, professional studio lighting setup blending into nature\'s light, 100mm macro lens, F1.8, 8k, photorealistic masterpiece.\\n\\n🎯 转化逻辑 (Marketing Logic)\\n实体感 (Physicality)：通过要求“部署（deployable）”的动作，自然地增加了椅腿和支撑结构之间的连接点，并强制要求在地面接触点和框架连接点生成环境光遮蔽（AO），这物理性地证明了椅子是一个由多个具有明确厚度和体积的独立部件搭建而成的结构。\\n\\n溢价点 (Premium Point)：重点强调了“航空级阳极氧化铝”和“弹道尼龙”，并要求捕捉“精密加工的接缝/接点”，这引导观看者关注其工业设计和材料的耐用性，将实用性转化为极具收藏价值的工艺品级别。\\n\\n🛠 物理进化要求（针对模型败笔）\\n体积禁令 (Thickness Mandate)：明确指令了“visible product thickness and volume”，要求模型渲染腿部和框架的交汇处必须有明确的厚度和层次感。\\n接触阴影 (Contact Shadows)：强制要求在与地面的所有接触点生成**环境光遮蔽（ambient occlusion）**，这是构建可信赖“落地感”的关键。\\n结构边缘 (Structural Edges)：强调了“precise machining marks visible on the aluminum joints”，确保所有机械连接的边缘都必须是硬挺、清晰且符合机械结构的。\\n绝对物理真实：光照设定在“soft, diffused natural light environment”，模拟了高质量的户外自然光，确保所有阴影和材质反射都遵循真实的光学定律。\", \"preview_markdown\": \"💎 视觉灵魂 (Visual Soul)\\nArchitectural Minimalism meets Rugged Expedition Luxury：以极简建筑美学和全地形探险的硬朗质感结合，强调产品在自然环境中的结构稳定性和材料的精密咬合感。\\n\\n📸 核心指令 (Copy-ready Prompt)\\nA pair of high-end, deployable folding outdoor chair, made of matte anodized aerospace aluminum and tightly woven, reinforced ballistic nylon. The chair is set up on a rough, weathered slate surface in a soft, diffused natural light environment. Must have visible product thickness and volume, clear separation between the chair legs/frame and the slate surface (or grass), physical soft shadows at all contact points (ambient occlusion), perfect structural integrity, visible grain and weave texture on the nylon, precise machining marks visible on the aluminum joints, cinematic depth of field, ray-traced reflections on polished aluminum joints, professional studio lighting setup blending into nature\'s light, 100mm macro lens, F1.8, 8k, photorealistic masterpiece.\\n\\n🎯 转化逻辑 (Marketing Logic)\\n实体感 (Physicality)：通过要求“部署（deployable）”的动作，自然地增加了椅腿和支撑结构之间的连接点，并强制要求在地面接触点和框架连接点生成环境光遮蔽（AO），这物理性地证明了椅子是一个由多个具有明确厚度和体积的独立部件搭建而成的结构。\\n\\n溢价点 (Premium Point)：重点强调了“航空级阳极氧化铝”和“弹道尼龙”，并要求捕捉“精密加工的接缝/接点”，这引导观看者关注其工业设计和材料的耐用性，将实用性转化为极具收藏价值的工艺品级别。\\n\\n🛠 物理进化要求（针对模型败笔）\\n体积禁令 (Thickness Mandate)：明确指令了“visible product thickness and volume”，要求模型渲染腿部和框架的交汇处必须有明确的厚度和层次感。\\n接触阴影 (Contact Shadows)：强制要求在与地面的所有接触点生成**环境光遮蔽（ambient occlusion）**，这是构建可信赖“落地感”的关键。\\n结构边缘 (Structural Edges)：强调了“precise machining marks visible on the aluminum joints”，确保所有机械连接的边缘都必须是硬挺、清晰且符合机械结构的。\\n绝对物理真实：光照设定在“soft, diffused natural light environment”，模拟了高质量的户外自然光，确保所有阴影和材质反射都遵循真实的光学定律。\"}, \"class_type\": \"PreviewAny\"}, \"64:3\": {\"_meta\": {\"title\": \"K采样器\"}, \"inputs\": {\"cfg\": 1, \"seed\": 1023311306257007, \"model\": [\"64:11\", 0], \"steps\": 8, \"denoise\": 1, \"negative\": [\"64:33\", 0], \"positive\": [\"64:27\", 0], \"scheduler\": \"simple\", \"latent_image\": [\"64:13\", 0], \"sampler_name\": \"res_multistep\"}, \"class_type\": \"KSampler\"}, \"64:8\": {\"_meta\": {\"title\": \"VAE解码\"}, \"inputs\": {\"vae\": [\"64:29\", 0], \"samples\": [\"64:3\", 0]}, \"class_type\": \"VAEDecode\"}, \"64:11\": {\"_meta\": {\"title\": \"采样算法（AuraFlow）\"}, \"inputs\": {\"model\": [\"64:28\", 0], \"shift\": 3}, \"class_type\": \"ModelSamplingAuraFlow\"}, \"64:13\": {\"_meta\": {\"title\": \"空Latent图像（SD3）\"}, \"inputs\": {\"width\": 1088, \"height\": 1088, \"batch_size\": 1}, \"class_type\": \"EmptySD3LatentImage\"}, \"64:27\": {\"_meta\": {\"title\": \"CLIP文本编码\"}, \"inputs\": {\"clip\": [\"64:30\", 0], \"text\": [\"69\", 0]}, \"class_type\": \"CLIPTextEncode\"}, \"64:28\": {\"_meta\": {\"title\": \"UNet加载器\"}, \"inputs\": {\"unet_name\": \"z_image_turbo_bf16.safetensors\", \"weight_dtype\": \"default\"}, \"class_type\": \"UNETLoader\"}, \"64:29\": {\"_meta\": {\"title\": \"加载VAE\"}, \"inputs\": {\"vae_name\": \"ae.safetensors\"}, \"class_type\": \"VAELoader\"}, \"64:30\": {\"_meta\": {\"title\": \"加载CLIP\"}, \"inputs\": {\"type\": \"lumina2\", \"device\": \"default\", \"clip_name\": \"qwen_3_4b.safetensors\"}, \"class_type\": \"CLIPLoader\"}, \"64:33\": {\"_meta\": {\"title\": \"条件零化\"}, \"inputs\": {\"conditioning\": [\"64:27\", 0]}, \"class_type\": \"ConditioningZeroOut\"}}','{\"seed\": {\"node\": \"64:3\", \"type\": \"number\", \"field\": \"seed\", \"label\": \"随机种子\", \"default\": 42}, \"steps\": {\"node\": \"64:3\", \"type\": \"number\", \"field\": \"steps\", \"label\": \"采样步数\", \"default\": 8}, \"width\": {\"node\": \"64:13\", \"type\": \"number\", \"field\": \"width\", \"label\": \"宽度\", \"default\": 1088}, \"height\": {\"node\": \"64:13\", \"type\": \"number\", \"field\": \"height\", \"label\": \"高度\", \"default\": 1088}, \"prompt\": {\"node\": \"69\", \"type\": \"textarea\", \"field\": \"prompt\", \"label\": \"提示词\", \"default\": \"一只可爱的蓝色机械猫\"}}',0,NULL,NULL,'2026-04-08 08:19:50','2026-04-10 21:30:15'),(2,'单图编辑一',NULL,NULL,'i2i_qwen_image_edit_default','i2i','1.0.0','{\"60\": {\"_meta\": {\"title\": \"保存图像\"}, \"inputs\": {\"images\": [\"102:8\", 0], \"filename_prefix\": \"ComfyUI\"}, \"class_type\": \"SaveImage\"}, \"78\": {\"_meta\": {\"title\": \"加载图像\"}, \"inputs\": {\"image\": \"20260410055420_b4b2b90e7eeb2806.png\"}, \"class_type\": \"LoadImage\"}, \"93\": {\"_meta\": {\"title\": \"缩放图像（像素）\"}, \"inputs\": {\"image\": [\"78\", 0], \"megapixels\": 1.5, \"upscale_method\": \"lanczos\", \"resolution_steps\": 1}, \"class_type\": \"ImageScaleToTotalPixels\"}, \"102:3\": {\"_meta\": {\"title\": \"K采样器\"}, \"inputs\": {\"cfg\": [\"102:109\", 0], \"seed\": 1118168676191618, \"model\": [\"102:75\", 0], \"steps\": [\"102:110\", 0], \"denoise\": 1, \"negative\": [\"102:77\", 0], \"positive\": [\"102:76\", 0], \"scheduler\": \"simple\", \"latent_image\": [\"102:88\", 0], \"sampler_name\": \"euler\"}, \"class_type\": \"KSampler\"}, \"102:8\": {\"_meta\": {\"title\": \"VAE解码\"}, \"inputs\": {\"vae\": [\"102:39\", 0], \"samples\": [\"102:3\", 0]}, \"class_type\": \"VAEDecode\"}, \"102:37\": {\"_meta\": {\"title\": \"UNet加载器\"}, \"inputs\": {\"unet_name\": \"qwen_image_edit_fp8_e4m3fn.safetensors\", \"weight_dtype\": \"default\"}, \"class_type\": \"UNETLoader\"}, \"102:38\": {\"_meta\": {\"title\": \"加载CLIP\"}, \"inputs\": {\"type\": \"qwen_image\", \"device\": \"default\", \"clip_name\": \"qwen_2.5_vl_7b_fp8_scaled.safetensors\"}, \"class_type\": \"CLIPLoader\"}, \"102:39\": {\"_meta\": {\"title\": \"加载VAE\"}, \"inputs\": {\"vae_name\": \"qwen_image_vae.safetensors\"}, \"class_type\": \"VAELoader\"}, \"102:66\": {\"_meta\": {\"title\": \"采样算法（AuraFlow）\"}, \"inputs\": {\"model\": [\"102:108\", 0], \"shift\": 3}, \"class_type\": \"ModelSamplingAuraFlow\"}, \"102:75\": {\"_meta\": {\"title\": \"CFG归一化\"}, \"inputs\": {\"model\": [\"102:66\", 0], \"strength\": 1}, \"class_type\": \"CFGNorm\"}, \"102:76\": {\"_meta\": {\"title\": \"文本编码（QwenImageEdit）\"}, \"inputs\": {\"vae\": [\"102:39\", 0], \"clip\": [\"102:38\", 0], \"image\": [\"93\", 0], \"prompt\": \"换成才彩色的，职业照,去掉眼镜\"}, \"class_type\": \"TextEncodeQwenImageEdit\"}, \"102:77\": {\"_meta\": {\"title\": \"文本编码（QwenImageEdit）\"}, \"inputs\": {\"vae\": [\"102:39\", 0], \"clip\": [\"102:38\", 0], \"image\": [\"93\", 0], \"prompt\": null}, \"class_type\": \"TextEncodeQwenImageEdit\"}, \"102:88\": {\"_meta\": {\"title\": \"VAE编码\"}, \"inputs\": {\"vae\": [\"102:39\", 0], \"pixels\": [\"93\", 0]}, \"class_type\": \"VAEEncode\"}, \"102:89\": {\"_meta\": {\"title\": \"LoRA加载器（仅模型）\"}, \"inputs\": {\"model\": [\"102:37\", 0], \"lora_name\": \"Qwen-Image-Edit-Lightning-4steps-V1.0-bf16.safetensors\", \"strength_model\": 1}, \"class_type\": \"LoraLoaderModelOnly\"}, \"102:103\": {\"_meta\": {\"title\": \"Steps\"}, \"inputs\": {\"value\": 4}, \"class_type\": \"PrimitiveInt\"}, \"102:105\": {\"_meta\": {\"title\": \"CFG\"}, \"inputs\": {\"value\": 1}, \"class_type\": \"PrimitiveFloat\"}, \"102:106\": {\"_meta\": {\"title\": \"Steps\"}, \"inputs\": {\"value\": 20}, \"class_type\": \"PrimitiveInt\"}, \"102:107\": {\"_meta\": {\"title\": \"CFG\"}, \"inputs\": {\"value\": 2.5}, \"class_type\": \"PrimitiveFloat\"}, \"102:108\": {\"_meta\": {\"title\": \"Switch (model)\"}, \"inputs\": {\"switch\": [\"102:111\", 0], \"on_true\": [\"102:89\", 0], \"on_false\": [\"102:37\", 0]}, \"class_type\": \"ComfySwitchNode\"}, \"102:109\": {\"_meta\": {\"title\": \"Switch (CFG)\"}, \"inputs\": {\"switch\": [\"102:111\", 0], \"on_true\": [\"102:105\", 0], \"on_false\": [\"102:107\", 0]}, \"class_type\": \"ComfySwitchNode\"}, \"102:110\": {\"_meta\": {\"title\": \"Switch (Steps)\"}, \"inputs\": {\"switch\": [\"102:111\", 0], \"on_true\": [\"102:103\", 0], \"on_false\": [\"102:106\", 0]}, \"class_type\": \"ComfySwitchNode\"}, \"102:111\": {\"_meta\": {\"title\": \"Enable 4steps LoRA\"}, \"inputs\": {\"value\": false}, \"class_type\": \"PrimitiveBoolean\"}}','{\"seed\": {\"node\": \"102:3\", \"type\": \"number\", \"field\": \"seed\", \"label\": \"种子\", \"default\": 76900311683723}, \"image\": {\"node\": \"78\", \"type\": \"image\", \"field\": \"image\", \"label\": \"输入图片\", \"default\": \"20260410055420_b4b2b90e7eeb2806.png\"}, \"prompt\": {\"node\": \"102:76\", \"type\": \"textarea\", \"field\": \"prompt\", \"label\": \"修改指令\", \"default\": \"更换背景\"}, \"strength\": {\"node\": \"102:3\", \"type\": \"number\", \"field\": \"denoise\", \"label\": \"重绘强度\", \"default\": 1}}',1,NULL,3,'2026-04-08 08:19:50','2026-04-10 20:41:15'),(3,'默认图生视频',NULL,NULL,'i2v_default','i2v','1.0.0','{\"75\": {\"_meta\": {\"title\": \"保存视频\"}, \"inputs\": {\"codec\": \"auto\", \"video\": [\"267:242\", 0], \"format\": \"auto\", \"filename_prefix\": \"video/LTX_2.3_i2v\"}, \"class_type\": \"SaveVideo\"}, \"269\": {\"_meta\": {\"title\": \"加载图像\"}, \"inputs\": {\"image\": \"z-image-turbo_00006_.png\"}, \"class_type\": \"LoadImage\"}, \"267:201\": {\"_meta\": {\"title\": \"Switch to Text to Video?\"}, \"inputs\": {\"value\": false}, \"class_type\": \"PrimitiveBoolean\"}, \"267:209\": {\"_meta\": {\"title\": \"K采样器选择\"}, \"inputs\": {\"sampler_name\": \"euler_ancestral_cfg_pp\"}, \"class_type\": \"KSamplerSelect\"}, \"267:211\": {\"_meta\": {\"title\": \"自定义Sigmas\"}, \"inputs\": {\"sigmas\": \"0.85, 0.7250, 0.4219, 0.0\"}, \"class_type\": \"ManualSigmas\"}, \"267:212\": {\"_meta\": {\"title\": \"LTXV裁剪指导\"}, \"inputs\": {\"latent\": [\"267:217\", 0], \"negative\": [\"267:239\", 1], \"positive\": [\"267:239\", 0]}, \"class_type\": \"LTXVCropGuides\"}, \"267:213\": {\"_meta\": {\"title\": \"CFG引导器\"}, \"inputs\": {\"cfg\": 1, \"model\": [\"267:232\", 0], \"negative\": [\"267:212\", 1], \"positive\": [\"267:212\", 0]}, \"class_type\": \"CFGGuider\"}, \"267:214\": {\"_meta\": {\"title\": \"LTXV 空音频潜空间\"}, \"inputs\": {\"audio_vae\": [\"267:221\", 0], \"batch_size\": 1, \"frame_rate\": [\"267:261\", 1], \"frames_number\": [\"267:225\", 0]}, \"class_type\": \"LTXVEmptyLatentAudio\"}, \"267:215\": {\"_meta\": {\"title\": \"自定义采样器（高级）\"}, \"inputs\": {\"noise\": [\"267:237\", 0], \"guider\": [\"267:231\", 0], \"sigmas\": [\"267:252\", 0], \"sampler\": [\"267:209\", 0], \"latent_image\": [\"267:222\", 0]}, \"class_type\": \"SamplerCustomAdvanced\"}, \"267:216\": {\"_meta\": {\"title\": \"随机噪波\"}, \"inputs\": {\"noise_seed\": 42}, \"class_type\": \"RandomNoise\"}, \"267:217\": {\"_meta\": {\"title\": \"LTXV分离音视频潜空间\"}, \"inputs\": {\"av_latent\": [\"267:215\", 0]}, \"class_type\": \"LTXVSeparateAVLatent\"}, \"267:218\": {\"_meta\": {\"title\": \"LTXV分离音视频潜空间\"}, \"inputs\": {\"av_latent\": [\"267:219\", 0]}, \"class_type\": \"LTXVSeparateAVLatent\"}, \"267:219\": {\"_meta\": {\"title\": \"自定义采样器（高级）\"}, \"inputs\": {\"noise\": [\"267:216\", 0], \"guider\": [\"267:213\", 0], \"sigmas\": [\"267:211\", 0], \"sampler\": [\"267:246\", 0], \"latent_image\": [\"267:229\", 0]}, \"class_type\": \"SamplerCustomAdvanced\"}, \"267:220\": {\"_meta\": {\"title\": \"LTXV音频VAE解码\"}, \"inputs\": {\"samples\": [\"267:218\", 1], \"audio_vae\": [\"267:221\", 0]}, \"class_type\": \"LTXVAudioVAEDecode\"}, \"267:221\": {\"_meta\": {\"title\": \"LTXV音频VAE加载器\"}, \"inputs\": {\"ckpt_name\": \"ltx-2.3-22b-distilled-fp8.safetensors\"}, \"class_type\": \"LTXVAudioVAELoader\"}, \"267:222\": {\"_meta\": {\"title\": \"LTXVConcatAVLatent\"}, \"inputs\": {\"audio_latent\": [\"267:214\", 0], \"video_latent\": [\"267:249\", 0]}, \"class_type\": \"LTXVConcatAVLatent\"}, \"267:225\": {\"_meta\": {\"title\": \"Length\"}, \"inputs\": {\"value\": 121}, \"class_type\": \"PrimitiveInt\"}, \"267:228\": {\"_meta\": {\"title\": \"空Latent视频（LTXV）\"}, \"inputs\": {\"width\": [\"267:256\", 1], \"height\": [\"267:259\", 1], \"length\": [\"267:225\", 0], \"batch_size\": 1}, \"class_type\": \"EmptyLTXVLatentVideo\"}, \"267:229\": {\"_meta\": {\"title\": \"LTXVConcatAVLatent\"}, \"inputs\": {\"audio_latent\": [\"267:217\", 1], \"video_latent\": [\"267:230\", 0]}, \"class_type\": \"LTXVConcatAVLatent\"}, \"267:230\": {\"_meta\": {\"title\": \"LTXV图像转视频（原地）\"}, \"inputs\": {\"vae\": [\"267:236\", 2], \"image\": [\"267:248\", 0], \"bypass\": [\"267:201\", 0], \"latent\": [\"267:253\", 0], \"strength\": 1}, \"class_type\": \"LTXVImgToVideoInplace\"}, \"267:231\": {\"_meta\": {\"title\": \"CFG引导器\"}, \"inputs\": {\"cfg\": 1, \"model\": [\"267:232\", 0], \"negative\": [\"267:239\", 1], \"positive\": [\"267:239\", 0]}, \"class_type\": \"CFGGuider\"}, \"267:232\": {\"_meta\": {\"title\": \"LoRA加载器（仅模型）\"}, \"inputs\": {\"model\": [\"267:236\", 0], \"lora_name\": \"ltx-2.3-22b-distilled-lora-384.safetensors\", \"strength_model\": 0.5}, \"class_type\": \"LoraLoaderModelOnly\"}, \"267:233\": {\"_meta\": {\"title\": \"加载Latent放大模型\"}, \"inputs\": {\"model_name\": \"ltx-2.3-spatial-upscaler-x2-1.1.safetensors\"}, \"class_type\": \"LatentUpscaleModelLoader\"}, \"267:235\": {\"_meta\": {\"title\": \"缩放图像（长边）\"}, \"inputs\": {\"images\": [\"267:238\", 0], \"longer_edge\": 1536}, \"class_type\": \"ResizeImagesByLongerEdge\"}, \"267:236\": {\"_meta\": {\"title\": \"Checkpoint加载器（简易）\"}, \"inputs\": {\"ckpt_name\": \"ltx-2.3-22b-distilled-fp8.safetensors\"}, \"class_type\": \"CheckpointLoaderSimple\"}, \"267:237\": {\"_meta\": {\"title\": \"随机噪波\"}, \"inputs\": {\"noise_seed\": 723381549937839}, \"class_type\": \"RandomNoise\"}, \"267:238\": {\"_meta\": {\"title\": \"调整图像/掩码大小\"}, \"inputs\": {\"input\": [\"269\", 0], \"resize_type\": \"scale dimensions\", \"scale_method\": \"lanczos\", \"resize_type.crop\": \"center\", \"resize_type.width\": [\"267:257\", 0], \"resize_type.height\": [\"267:258\", 0]}, \"class_type\": \"ResizeImageMaskNode\"}, \"267:239\": {\"_meta\": {\"title\": \"LTXV条件\"}, \"inputs\": {\"negative\": [\"267:247\", 0], \"positive\": [\"267:240\", 0], \"frame_rate\": [\"267:261\", 0]}, \"class_type\": \"LTXVConditioning\"}, \"267:240\": {\"_meta\": {\"title\": \"CLIP文本编码\"}, \"inputs\": {\"clip\": [\"267:243\", 0], \"text\": [\"267:274\", 0]}, \"class_type\": \"CLIPTextEncode\"}, \"267:242\": {\"_meta\": {\"title\": \"创建视频\"}, \"inputs\": {\"fps\": [\"267:261\", 0], \"audio\": [\"267:220\", 0], \"images\": [\"