 {\"_meta\": {\"title\": \"Height\"}, \"inputs\": {\"value\": 720}, \"class_type\": \"PrimitiveInt\"}, \"267:259\": {\"_meta\": {\"title\": \"Math Expression\"}, \"inputs\": {\"values.a\": [\"267:258\", 0], \"expression\": \"a/2\"}, \"class_type\": \"ComfyMathExpression\"}, \"267:260\": {\"_meta\": {\"title\": \"Frame Rate\"}, \"inputs\": {\"value\": 25}, \"class_type\": \"PrimitiveInt\"}, \"267:261\": {\"_meta\": {\"title\": \"Math Expression\"}, \"inputs\": {\"values.a\": [\"267:260\", 0], \"expression\": \"a\"}, \"class_type\": \"ComfyMathExpression\"}, \"267:266\": {\"_meta\": {\"title\": \"Prompt\"}, \"inputs\": {\"value\": \"Egyptian royal in blue-and-gold headdress and high collar, white dress with golden embroidery and armbands, desert, robot soldiers in formation left and right. She walks steadily forward, head held level and gaze fixed ahead—no dipping or lowering of the head. The camera performs a single, smooth push-in only: starting in a wider shot of her, the robots, and the desert, it moves steadily forward until she is in a medium or medium-close frame, then holds. She stops, posture and head still upright, and says: “The old gods are silent. I am not.” Robot soldiers shift or march in place; sand and fabric move with the wind. No pull-back; the only camera move is the continuous push-in.\"}, \"class_type\": \"PrimitiveStringMultiline\"}, \"267:272\": {\"_meta\": {\"title\": \"加载LoRA\"}, \"inputs\": {\"clip\": [\"267:243\", 0], \"model\": [\"267:236\", 0], \"lora_name\": \"gemma-3-12b-it-abliterated_lora_rank64_bf16.safetensors\", \"strength_clip\": 1, \"strength_model\": 1}, \"class_type\": \"LoraLoader\"}, \"267:274\": {\"_meta\": {\"title\": \"TextGenerateLTX2Prompt\"}, \"inputs\": {\"clip\": [\"267:272\", 1], \"image\": [\"269\", 0], \"prompt\": [\"267:266\", 0], \"max_length\": 256, \"sampling_mode\": \"on\", \"sampling_mode.seed\": 0, \"sampling_mode.min_p\": 0.05, \"sampling_mode.top_k\": 64, \"sampling_mode.top_p\": 0.95, \"sampling_mode.temperature\": 0.7, \"sampling_mode.repetition_penalty\": 1.05}, \"class_type\": \"TextGenerateLTX2Prompt\"}, \"267:275\": {\"_meta\": {\"title\": \"预览任意\"}, \"inputs\": {\"source\": [\"267:274\", 0], \"previewMode\": null, \"preview_text\": \"\", \"preview_markdown\": \"\"}, \"class_type\": \"PreviewAny\"}}','{\"seed\": {\"node\": \"14\", \"type\": \"number\", \"field\": \"seed\", \"label\": \"随机种子\", \"default\": 42}, \"image\": {\"node\": \"6\", \"type\": \"image\", \"field\": \"image\", \"label\": \"启动图片\", \"default\": \"\"}, \"width\": {\"node\": \"13\", \"type\": \"number\", \"field\": \"width\", \"label\": \"宽度\", \"default\": 720}, \"height\": {\"node\": \"13\", \"type\": \"number\", \"field\": \"height\", \"label\": \"高度\", \"default\": 1280}, \"prompt\": {\"node\": \"5\", \"type\": \"textarea\", \"field\": \"prompt\", \"label\": \"提示词\", \"default\": \"\"}}',1,NULL,NULL,'2026-04-08 08:19:50','2026-04-08 14:30:48'),(4,'默认文生视频',NULL,NULL,'t2v_default','t2v','1.0.0','{\"10\": {\"_meta\": {\"title\": \"KSampler\"}, \"inputs\": {\"cfg\": 2.5, \"seed\": 42, \"model\": [\"11\", 0], \"steps\": 20, \"denoise\": 1, \"negative\": [\"11\", 2], \"positive\": [\"11\", 1], \"scheduler\": \"karras\", \"latent_image\": [\"11\", 3], \"sampler_name\": \"euler\"}, \"class_type\": \"KSampler\"}, \"11\": {\"_meta\": {\"title\": \"SVD Conditioning\"}, \"inputs\": {\"fps\": 6, \"width\": 512, \"height\": 512, \"init_image\": [\"12\", 0], \"clip_vision\": [\"15\", 0], \"video_frames\": 14, \"motion_bucket_id\": 127, \"augmentation_level\": 0}, \"class_type\": \"SVD_img2vid_Conditioning\"}, \"12\": {\"_meta\": {\"title\": \"Load Image\"}, \"inputs\": {\"image\": \"input_image.png\", \"upload\": \"image\"}, \"class_type\": \"LoadImage\"}, \"13\": {\"_meta\": {\"title\": \"VAE Decode\"}, \"inputs\": {\"vae\": [\"14\", 0], \"samples\": [\"10\", 0]}, \"class_type\": \"VAEDecode\"}, \"14\": {\"_meta\": {\"title\": \"Load VAE\"}, \"inputs\": {\"vae_name\": \"video_vae.safetensors\"}, \"class_type\": \"VAELoader\"}, \"15\": {\"_meta\": {\"title\": \"Load CLIP Vision\"}, \"inputs\": {\"clip_name\": \"clip_vision_g.safetensors\"}, \"class_type\": \"CLIPVisionLoader\"}, \"16\": {\"_meta\": {\"title\": \"Save Video Frames\"}, \"inputs\": {\"images\": [\"13\", 0], \"filename_prefix\": \"Beikuman_Video\"}, \"class_type\": \"SaveImage\"}}','{\"prompt\": {\"node\": \"5\", \"type\": \"textarea\", \"field\": \"prompt\", \"label\": \"提示词\", \"default\": \"\"}}',1,NULL,NULL,'2026-04-08 08:19:50','2026-04-08 14:30:49'),(5,'通用文生图一',NULL,NULL,'t2i_1','t2i','1.0.0','{\"63\": {\"_meta\": {\"title\": \"保存图像\"}, \"inputs\": {\"images\": [\"64:8\", 0], \"filename_prefix\": \"z-image-turbo\"}, \"class_type\": \"SaveImage\"}, \"68\": {\"_meta\": {\"title\": \"Ollama Connectivity\"}, \"inputs\": {\"url\": \"http://127.0.0.1:11434\", \"model\": \"gemma4:latest\", \"keep_alive\": 5, \"keep_alive_unit\": \"minutes\"}, \"class_type\": \"OllamaConnectivityV2\"}, \"69\": {\"_meta\": {\"title\": \"Ollama Generate\"}, \"inputs\": {\"think\": false, \"format\": \"text\", \"prompt\": \"户外折叠椅。\", \"system\": \"Role\\n您是一位享誉全球的顶级商业摄影大师与视觉物理专家。你不仅拥有极致的审美，更对物体的物理结构和材质真实感有着偏执的追求。你的任务是将任何产品关键词转化为具有顶级溢价感、电影级影调，且绝对符合物理逻辑的专业商业摄影 Prompt。你绝不允许出现物体穿模、材质融合等廉价错误。\\n\\nTask\\n将用户的关键词转化为顶级商业摄影指令，旨在通过视觉质感激发用户的占有欲。\\n\\nOutput Format (严格遵守 Markdown)\\n💎 视觉灵魂 (Visual Soul)\\n[定义一种高溢价感的摄影风格，如：Cinematic Realism / High-Tech Still Life / Ethical Luxury Portrait。强调画面在极致美学下的物理真实性。]\\n\\n📸 核心指令 (Copy-ready Prompt)\\n[英文 Prompt 必须严格遵循禁令：no text, no words, no watermark, no logo。\\n强制物理实体堆栈：Must have visible product thickness and volume, clear separation between object and contact surface (or skin), physical soft shadows at contact points (ambient occlusion), structural integrity, premium material textures (e.g., woven tech-fabric with thickness, defined stitching), ray-traced reflections, professional studio lighting, 100mm macro lens, F1.8, 8k, photorealistic masterpiece.]\\n\\n🎯 转化逻辑 (Marketing Logic)\\n实体感 (Physicality)：描述画面如何体现产品的“真实存在感”，例如：通过微小的厚度差和接触点的阴影，强调它是一个独立的、高质量的实体。\\n\\n溢价点 (Premium Point)：解释如何利用工艺细节（如：精细的接缝、扎实的材料）而非不真实的虚幻感来提升价值。\\n\\n🛠 物理进化要求（针对模型败笔）\\n体积禁令 (Thickness Mandate)：Prompt 必须明确描述产品的体积和厚度。如果是织物覆盖类产品，必须体现出它是一个“盖在（over）”上方，而非“融在（fused with）”上方的独立实体。\\n\\n接触阴影 (Contact Shadows)：强制使用**环境光遮蔽（Ambient Occlusion）**指令。在物体与人体的接触点，必须生成自然的、微小的物理软阴影，以此证明物体的独立存在。\\n\\n结构边缘 (Structural Edges)：产品的边缘必须清晰、硬挺（符合产品自身结构），严禁出现边缘虚化或与背景/人体材质融合的现象。\\n\\n绝对物理真实：画面中所有光影、材质和物体接触必须符合基本的物理常识。\\n\\nConstraint\\n直接输出指令，严禁任何废话。如果用户提供特定产品，则根据该产品材质特征进行光影和体积适配，核心指令堆栈必须保持通用、高端且符合物理逻辑。\", \"connectivity\": [\"68\", 0], \"keep_context\": false}, \"class_type\": \"OllamaGenerateV2\"}, \"64:3\": {\"_meta\": {\"title\": \"K采样器\"}, \"inputs\": {\"cfg\": 1, \"seed\": 1023311306257007, \"model\": [\"64:11\", 0], \"steps\": 8, \"denoise\": 1, \"negative\": [\"64:33\", 0], \"positive\": [\"64:27\", 0], \"scheduler\": \"simple\", \"latent_image\": [\"64:13\", 0], \"sampler_name\": \"res_multistep\"}, \"class_type\": \"KSampler\"}, \"64:8\": {\"_meta\": {\"title\": \"VAE解码\"}, \"inputs\": {\"vae\": [\"64:29\", 0], \"samples\": [\"64:3\", 0]}, \"class_type\": \"VAEDecode\"}, \"64:11\": {\"_meta\": {\"title\": \"采样算法（AuraFlow）\"}, \"inputs\": {\"model\": [\"64:28\", 0], \"shift\": 3}, \"class_type\": \"ModelSamplingAuraFlow\"}, \"64:13\": {\"_meta\": {\"title\": \"空Latent图像（SD3）\"}, \"inputs\": {\"width\": 1088, \"height\": 1088, \"batch_size\": 1}, \"class_type\": \"EmptySD3LatentImage\"}, \"64:27\": {\"_meta\": {\"title\": \"CLIP文本编码\"}, \"inputs\": {\"clip\": [\"64:30\", 0], \"text\": [\"69\", 0]}, \"class_type\": \"CLIPTextEncode\"}, \"64:28\": {\"_meta\": {\"title\": \"UNet加载器\"}, \"inputs\": {\"unet_name\": \"z_image_turbo_bf16.safetensors\", \"weight_dtype\": \"default\"}, \"class_type\": \"UNETLoader\"}, \"64:29\": {\"_meta\": {\"title\": \"加载VAE\"}, \"inputs\": {\"vae_name\": \"ae.safetensors\"}, \"class_type\": \"VAELoader\"}, \"64:30\": {\"_meta\": {\"title\": \"加载CLIP\"}, \"inputs\": {\"